sql:
SELECT resort_name, total_accommodations
FROM resorts
ORDER BY total_accommodations DESC;

external_knowledge:
- 'well-established gems' refers to resorts with high average ratings and a large number of accommodations; 
- '21st-century portfolio' refers to resorts added after the year 2000; 
- 'shining with above-average guest satisfaction' refers to resorts with an average rating greater than 3.5 out of 5.

