SELECT resort_name, total_employees
FROM resorts
ORDER BY total_employees DESC;

SELECT DISTINCT c.country_name
FROM countries c
JOIN resorts r ON c.country_id = r.country_id;

SELECT DISTINCT c.country_name
FROM countries c
JOIN resorts r ON c.country_id = r.country_id;

external_knowledge:
- 'major transformations' refers to renovations or expansions; 
- 'milestones' refers to significant events of type 'renovation' or 'expansion'; 
- 'average departmental workforce size' refers to the average number of employees per department.
